$q=$pdo->prepare('SELECT * FROM pedido_detalles WHERE pedido_id=:id');$q->execute(['id'=>$id]);$det=$q->fetchAll();$q=$pdo->prepare("SELECT h.*,CONCAT_WS(' ',u.nombre,u.apellido) responsable FROM pedido_historial h LEFT JOIN usuarios u ON u.id=h.usuario_id WHERE h.pedido_id=:id ORDER BY h.created_at");$q->execute(['id'=>$id]);$hist=$q->fetchAll();
