<div class="col-lg-4"><div class="card card-rounded"><div class="card-body"><h2 class="h5">Resumen</h2><p><strong>Cliente:</strong><br><?=atenea_e(trim($p['nombre'].' '.$p['apellido']))?><br><?=atenea_e($p['correo'])?></p><p><strong>Dirección:</strong><br><?=atenea_e((string)($direccion['receptor']??''))?> · <?=atenea_e((string)($direccion['telefono']??''))?><br><?=atenea_e((string)($direccion['direccion_detallada']??'No disponible'))?></p><p><strong>Pago:</strong> <?=$p['payment_status']==='paid'?'Pago completado':'Pendiente'?><br><strong>Seguimiento:</strong> <?=atenea_e(etiquetaSeguimientoPedido($p['estado_pedido']))?><br><strong>Total:</strong> $<?=number_format((float)$p['total'],2)?> <?=strtoupper($p['moneda'])?></p>
<?php if($p['comprobante_id']&&$p['payment_status']==='paid'):?><a class="btn btn-outline-primary w-100 mb-2" href="<?=atenea_url('src/comprobantes/descargar.php?pedido='.$id.'&tipo=pdf')?>">Descargar PDF</a><a class="btn btn-outline-primary w-100 mb-3" href="<?=atenea_url('src/comprobantes/descargar.php?pedido='.$id.'&tipo=json')?>">Descargar JSON</a><?php endif;?>
